SELECT DISTINCT year
FROM landings
ORDER BY year ASC;

SELECT avg_price
FROM price_trends
WHERE species_id = 0 AND year = 2007;

SELECT entity_name
FROM fishing_entities
WHERE country = 'USA';

SELECT SUM(catch_value) AS total_catch_value
FROM fisheries_data
WHERE species_id = 1 AND year = 2022;
